      tasks: state.exercise.tasks,
      activeTaskIndex: state.currentTaskIndex,
      disableSystemKeyboard,
    });
  }, [state.exercise, colorScheme, id, editorTheme, codeFontSize, ctaColor]);

 const styles = useMemo(
