 },
 backButtonText: {
  fontFamily: "JetBrainsMono",
  fontWeight: "900",
  fontSize: 13,
  letterSpacing: 0.5,
  color: colors.onPrimary,
 },
 container: {
 flex: 1,
 backgroundColor: colors.surface,
 },
 header: {
 flexDirection: "row",
 alignItems: "center",
 paddingHorizontal: 16,
 paddingBottom: 12,
 backgroundColor: colors.surface,
 },
 menuButton: {
 padding: 8,
 },
  logoText: {
    fontFamily: "JetBrainsMono",
    fontSize: 20,
    fontWeight: "700",
    color: colors.onSurface,
    marginLeft: 8,
    letterSpacing: -0.5,
  },
 spacer: {
 flex: 1,
 },
 webview: {
 flex: 1,
 },
 keyboardFab: {
 position: "absolute",
 right: 16,
 width: 48,
 height: 48,
 borderRadius: 9999,
 backgroundColor: colors.surfaceContainerHigh,
 alignItems: "center",
 justifyContent: "center",
