 const handleFormat = useCallback(() => {
 if (webViewRef.current && editorViewReady) {
 webViewRef.current.postMessage(JSON.stringify({ type: "format" }));
 }
 }, [editorViewReady]);

 const handleCursorMove = useCallback((direction: 'left' | 'right' | 'up' | 'down') => {
 if (webViewRef.current && editorViewReady) {
