        ]}
      />

      <ScrollView
 style={styles.scrollView}
 contentContainerStyle={styles.scrollContent}
 >
 {nextExercise && (
 <View
 style={[
 styles.heroSection,
 { backgroundColor: colors.surfaceContainerLow },
