 >
  <Text style={[styles.heroLabel, { color: derivedColors.primary }]}>
  Next exercise
  </Text>
 <Text style={[styles.heroTitle, { color: colors.onSurface }]}>
 {nextExercise.title}
 </Text>
 <View style={styles.heroDescriptionRow}>
 <View
