 </View>
 </View>
)}

 {upNextLessons.length > 0 && (
 <View style={styles.section}>
 <View style={styles.sectionHeader}>
 <Text style={[styles.sectionTitle, { color: derivedColors.primary }]}>
 Up Next
 </Text>
