 const locked = isLessonLocked(globalIdx);
 const isLast = index === upNextLessons.length - 1;
 return (
 <Pressable
 key={lesson.id}
 disabled={locked}
 onPress={() =>
 router.push(`/learn/${course}/${lesson.id}`)
 }
 style={({ pressed }) => [
  styles.lessonRow,
  isLast && styles.lessonRowLast,
  { borderColor: locked ? "transparent" : colors.outlineVariant },
  pressed &&
  !locked && {
  backgroundColor: colors.surfaceContainerHigh,
  },
  ]}
  >
  <View
  style={[
  styles.lessonIcon,
  { borderColor: locked ? "transparent" : colors.outlineVariant },
  ]}
 >
 {locked || isLast ? (
 <MaterialCommunityIcons
 name={isLast ? "trophy" : "lock"}
 size={20}
 color={isLast ? derivedColors.primary : colors.textSecondary}
 />
) : (
 <MaterialCommunityIcons
 name="play-circle-outline"
 size={20}
 color={derivedColors.primary}
 />
)}
 </View>
 <View style={styles.lessonInfo}>
 <Text
 style={[
 styles.lessonTitle,
 {
 color: locked
 ? colors.textSecondary
 : colors.onSurface,
 },
 ]}
 >
 {lesson.title}
 </Text>
 <Text
 style={[
 styles.lessonModule,
 { color: colors.textSecondary },
 ]}
 >
 {isLast
