  : lesson.module}
 </Text>
 </View>
 <MaterialCommunityIcons
 name="chevron-right"
 size={20}
 color={colors.textSecondary}
 />
 </Pressable>
);
 })}
 </View>
 </View>
)}

 {completedLessonItems.length > 0 && (
 <View
