    font-family: 'JetBrains Mono';
    font-style: normal;
    font-weight: 700;
    src: url(data:font/truetype;charset=utf-8;base64,${JETBRAINS_MONO_BOLD_BASE64}) format('truetype');
  }
  * { margin: 0; padding: 0; box-sizing: border-box; }
