    padding: 16px;
    background: ${colors.surfaceContainer};
  }
  .description-text {
    font-size: 15px;
    line-height: 22px;
    color: ${colors.onSurfaceVariant};
    white-space: pre-line;
  }
  .symbol {
    font-weight: 700;
    text-decoration: underline;
    color: ${cta};
    cursor: pointer;
  }

  .preview-section {
    margin-top: 16px;
    padding: 0;
    position: relative;
  }
  .preview-label {
    font-family: "JetBrains Mono", monospace;
    font-size: 12px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: ${colors.onSurfaceVariant};
    margin-bottom: 8px;
  }
  .preview-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 8px;
    padding: 0 16px;
  }
  .maximize-btn {
    background: ${colors.surfaceContainerHigh};
    border: 1px solid ${colors.outlineVariant};
    border-radius: 6px;
    padding: 4px 8px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 10;
  }
  .maximize-btn:active { opacity: 0.7; }
  .sketch-box {
    height: 180px;
    background: #000000;
    border-radius: 0;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    transition: height 0.3s ease;
  }
  .sketch-box.expanded {
    height: 400px;
    border-radius: 0;
  }
   .sketch-box canvas { display: block; touch-action: pan-y !important; }
  .run-btn {
    position: absolute;
    bottom: 8px;
    right: 8px;
    background: ${ctaColor};
    color: #fff;
    border: none;
    border-radius: 20px;
    padding: 6px 14px;
    font-family: "JetBrains Mono", monospace;
    font-size: 12px;
    font-weight: 700;
    cursor: pointer;
    z-index: 10;
    opacity: 0.9;
  }
  .run-btn:active { opacity: 0.7; }

  .solution-section {
    margin-top: 16px;
    padding: 0 16px;
  }
  .solution-header {
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
    cursor: pointer;
    background: none;
    border: none;
    width: 100%;
    padding: 10px 14px;
    border-radius: 10px;
    background: ${colors.surfaceContainerHigh};
  }
  .solution-header:active { opacity: 0.7; }

  .editor-section {
    margin-top: 20px;
    margin-left: 20px;
    margin-right: 20px;
    border-radius: 8px;
    overflow: hidden;
    background: ${editorBg};
    min-height: 400px;
    position: relative;
  }
  .editor-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 8px 12px 0 12px;
  }
  .editor-header-left {
    display: flex;
    align-items: center;
    gap: 8px;
  }
  .code-label {
    font-family: "JetBrains Mono", monospace;
    font-size: 12px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: ${colors.onSurfaceVariant};
  }
  .lang-tag {
    font-family: "JetBrains Mono", monospace;
    font-size: 11px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: ${cta};
    background: rgba(${ctaRgb}, 0.12);
    padding: 2px 6px;
    border-radius: 3px;
  }
  .editor-header-right {
    display: flex;
    gap: 6px;
  }
  .editor-header-btn {
    background: none;
    border: 1px solid ${colors.outlineVariant};
    color: ${colors.onSurfaceVariant};
    font-family: "JetBrains Mono", monospace;
    font-size: 11px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    padding: 3px 8px;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.2s ease;
  }
  .editor-header-btn:active {
    background: ${colors.primaryContainer}44;
  }
  .cm-editor { height: 100%; font-size: ${fontSize}px; background: ${editorBg}; }
  .cm-editor .cm-scroller { font-family: 'JetBrains Mono', monospace; overflow: auto; }
  .cm-editor.cm-focused { outline: none; }
  .cm-editor .cm-cursor { display: block !important; }
  .cm-editor .cm-gutters { background: ${editorBg}; border-right: 1px solid ${params.colorScheme === 'dark' ? '#292A2E' : '#E5E7EB'}; color: ${params.colorScheme === 'dark' ? '#6B7280' : '#9CA3AF'}; }
  .cm-editor .cm-activeLineGutter { background: ${params.colorScheme === 'dark' ? 'rgba(255,255,255,0.03)' : 'rgba(0,0,0,0.03)'}; }
  .cm-editor .cm-activeLine { background: ${params.colorScheme === 'dark' ? 'rgba(255,255,255,0.03)' : 'rgba(0,0,0,0.03)'}; }
  .cm-editor .cm-selectionBackground,
  .cm-editor.cm-focused .cm-selectionBackground { background: ${params.colorScheme === 'dark' ? 'rgba(255, 105, 180, 0.2)' : 'rgba(255, 105, 180, 0.15)'} !important; }
  .cm-editor .cm-matchingBracket {
